/**
 * Per-control assessment questionnaires for NIST CSF 2.0 — v2.
 *
 * v2 design rules (this is the rigor the platform commits to):
 *   1. Every question references a SPECIFIC named artifact, tool, system,
 *      regulation, threshold, or measurement. No vague "is there a process".
 *   2. Question STRUCTURE varies across controls — some ask the assessor to
 *      open a console, some ask for a quote, some ask "name three", some
 *      ask for a sample audit, some ask for a numeric measurement vs. a
 *      target. The previous v1 wording all started "Is there a written X"
 *      which made the questionnaire feel templated.
 *   3. Hints are written as explicit "Yes = X, Partial = Y, No = Z" rubric
 *      so the assessor (or future automation) has zero room to fudge.
 *   4. Q4 prompts are control-specific — they ask about an actual change or
 *      lesson learned, not a generic "describe an improvement".
 *
 * The data model is unchanged from v1: q1/q2/q3 each get a No/Partial/Yes
 * answer that maps to the CMM ladder (1 sum=0 → 4 sum=3, +1 if Q4 filled
 * and Q1-3 all Yes). Only the question CONTENT changed. Existing saved
 * responses continue to work.
 *
 * AssessmentWizard.tsx looks up the entry by control_id; if a control is
 * missing here it falls back to the generic CMM ladder questions defined
 * in the same component.
 */

export interface ControlQuestionnaire {
  q1: string;
  q1_hint: string;
  q2: string;
  q2_hint: string;
  q3: string;
  q3_hint: string;
  q4_prompt: string;
}

